mapper.select:
SELECT fsr.id, fsr.first_company_id AS firstCompanyId, fsr.second_company_id AS secondCompanyId, fc.company_name AS firstCompanyName, sc.company_name AS secondCompanyName, fsr.status, fsr.remark, fsr.create_time AS createTime FROM first_second_relation fsr LEFT JOIN sys_company fc ON fsr.first_company_id = fc.id LEFT JOIN sys_company sc ON fsr.second_company_id = sc.id
AND fsr.first_company_id = #{query.firstCompanyId}
AND fsr.second_company_id = #{query.secondCompanyId}
ORDER BY fsr.id DESC
